package com.wjx871.population.cancellation; import java.time.*;
public record CancellationView(Long cancellationId,String cancellationNo,Long applicationId,CancelObjectType cancelObjectType,Long personId,Long householdId,CancelReasonCode cancelReasonCode,String cancelReasonDetail,LocalDate eventDate,CancellationStatus businessStatus,String personName,String identityNo,String householdNo,String address,String regionCode,Long operatorId,LocalDateTime executedAt,Integer version){public static CancellationView from(CancellationRecord r,boolean full){return new CancellationView(r.getCancellationId(),r.getCancellationNo(),r.getApplicationId(),r.getCancelObjectType(),r.getPersonId(),r.getHouseholdId(),r.getCancelReasonCode(),r.getCancelReasonDetail(),r.getEventDate(),r.getBusinessStatus(),r.getPersonNameSnapshot(),full?r.getIdentityNoSnapshot():mask(r.getIdentityNoSnapshot()),r.getHouseholdNoSnapshot(),r.getAddressSnapshot(),r.getRegionCodeSnapshot(),r.getOperatorId(),r.getExecutedAt(),r.getVersion());}private static String mask(String v){return v==null||v.length()<8?"****":v.substring(0,4)+"**********"+v.substring(v.length()-4);}}
